use tauri::{
    image::Image,
    menu::{Menu, MenuItem, PredefinedMenuItem},
    tray::{TrayIcon, TrayIconBuilder},
    AppHandle, Manager, Runtime,
};

fn update_tray_icon<R: Runtime>(tray: &TrayIcon<R>, is_active: bool) {
    let icon_bytes: &[u8] = if is_active {
        include_bytes!("../icons/tray-active.png")
    } else {
        include_bytes!("../icons/tray-inactive.png")
    };
    if let Ok(icon) = Image::from_bytes(icon_bytes) {
        let _ = tray.set_icon(Some(icon));
    }
}

pub fn create_tray<R: Runtime>(app: &AppHandle<R>) -> tauri::Result<()> {
    let toggle_i = MenuItem::with_id(app, "toggle", "Disable", true, None::<&str>)?;
    let separator0 = PredefinedMenuItem::separator(app)?;
    let resume_i = MenuItem::with_id(app, "resume", "Resume", false, None::<&str>)?;
    let pause_30_i = MenuItem::with_id(app, "pause_30", "Pause 30 min", true, None::<&str>)?;
    let pause_60_i = MenuItem::with_id(app, "pause_60", "Pause 1 hour", true, None::<&str>)?;
    let separator1 = PredefinedMenuItem::separator(app)?;
    let settings_i = MenuItem::with_id(app, "settings", "Settings...", true, None::<&str>)?;
    let separator2 = PredefinedMenuItem::separator(app)?;
    let quit_i = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;

    let menu = Menu::with_items(
        app,
        &[
            &toggle_i,
            &separator0,
            &resume_i,
            &pause_30_i,
            &pause_60_i,
            &separator1,
            &settings_i,
            &separator2,
            &quit_i,
        ],
    )?;

    let icon = Image::from_bytes(include_bytes!("../icons/tray-active.png"))
        .expect("Failed to load tray icon");

    // Show "DEV" label next to icon in debug builds to distinguish from production
    #[cfg(debug_assertions)]
    let tray_title = Some("DEV");
    #[cfg(not(debug_assertions))]
    let tray_title: Option<&str> = None;

    let mut builder = TrayIconBuilder::with_id("main")
        .icon(icon)
        .icon_as_template(false)
        .menu(&menu)
        .show_menu_on_left_click(true);

    // Set title only in dev mode (shows text next to icon on macOS)
    if let Some(title) = tray_title {
        builder = builder.title(title);
    }

    let _ = builder
        .on_menu_event(move |app, event| {
            // Helper to update pause-related menu items
            let update_pause_menu = |is_paused: bool, remaining: Option<u32>| {
                if is_paused {
                    if let Some(mins) = remaining {
                        let _ = resume_i.set_text(&format!("Resume ({} min left)", mins));
                    } else {
                        let _ = resume_i.set_text("Resume");
                    }
                    let _ = resume_i.set_enabled(true);
                    let _ = pause_30_i.set_enabled(false);
                    let _ = pause_60_i.set_enabled(false);
                } else {
                    let _ = resume_i.set_text("Resume");
                    let _ = resume_i.set_enabled(false);
                    let _ = pause_30_i.set_enabled(true);
                    let _ = pause_60_i.set_enabled(true);
                }
            };

            // Update menu state when menu event occurs
            {
                let state = app.state::<crate::AppState>();
                let keeper = state.keeper.lock().unwrap();
                let is_running = keeper.is_running();

                // Update toggle text
                if is_running {
                    let _ = toggle_i.set_text("Disable");
                } else {
                    let _ = toggle_i.set_text("Enable");
                }

                // Update tray icon to reflect current state
                if let Some(tray) = app.tray_by_id("main") {
                    update_tray_icon(&tray, is_running);
                }

                // Update pause status
                update_pause_menu(keeper.is_paused(), keeper.pause_remaining_minutes());
            }

            match event.id.as_ref() {
                "toggle" => {
                    let state = app.state::<crate::AppState>();
                    let mut keeper = state.keeper.lock().unwrap();
                    let is_running = keeper.is_running();
                    if is_running {
                        keeper.stop();
                        let _ = toggle_i.set_text("Enable");
                    } else {
                        keeper.start();
                        let _ = toggle_i.set_text("Disable");
                    }
                    // Update tray icon to reflect the new state
                    if let Some(tray) = app.tray_by_id("main") {
                        update_tray_icon(&tray, !is_running);
                    }
                }
                "resume" => {
                    let state = app.state::<crate::AppState>();
                    let mut keeper = state.keeper.lock().unwrap();
                    keeper.resume();
                    update_pause_menu(false, None);
                }
                "pause_30" => {
                    let state = app.state::<crate::AppState>();
                    let mut keeper = state.keeper.lock().unwrap();
                    keeper.pause(30);
                    update_pause_menu(true, Some(30));
                }
                "pause_60" => {
                    let state = app.state::<crate::AppState>();
                    let mut keeper = state.keeper.lock().unwrap();
                    keeper.pause(60);
                    update_pause_menu(true, Some(60));
                }
                "settings" => {
                    if let Some(window) = app.get_webview_window("main") {
                        let _ = window.show();
                        let _ = window.set_focus();
                    }
                }
                "quit" => {
                    let state = app.state::<crate::AppState>();
                    let mut keeper = state.keeper.lock().unwrap();
                    keeper.stop();
                    drop(keeper);
                    crate::request_exit();
                    app.exit(0);
                }
                _ => {}
